// AllScale Org Chart — components

const { useState: useS, useEffect: useE, useRef: useR } = React;

// =========================================================================
// HEADER
// =========================================================================

function Header({
  query, setQuery, matchCount, totalPeople, execCount, deptCount,
  onAddExec, onAddPerson, onReset, zoom, setZoom,
  editMode, onToggleEditMode,
  sync, onPublish, onPullLatest,
}) {
  return (
    <header className="topbar">
      <div className="topbar-left">
        <span className="logo-wordmark" aria-label="AllScale" dangerouslySetInnerHTML={{ __html: ALLSCALE_LOGO_SVG }} />
        <div className="logo-text">
          <div className="logo-title">Org chart</div>
          <div className="logo-sub">{totalPeople} people · {execCount} leaders · {deptCount} departments</div>
        </div>
      </div>

      <div className="topbar-search">
        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <circle cx="11" cy="11" r="7"/>
          <path d="m20 20-3.5-3.5"/>
        </svg>
        <input
          id="org-search"
          type="text"
          placeholder="Search people, roles, departments…"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
        />
        {query && (
          <span className="search-count">{matchCount} match{matchCount === 1 ? "" : "es"}</span>
        )}
        <kbd className="kbd">⌘K</kbd>
      </div>

      <div className="topbar-right">
        <SyncStatus sync={sync} editMode={editMode} onPublish={onPublish} onPullLatest={onPullLatest} />
        <div className="zoom">
          <button className="z-btn" onClick={() => setZoom(z => Math.max(0.5, +(z - 0.1).toFixed(2)))} title="Zoom out">−</button>
          <span className="z-val">{Math.round(zoom * 100)}%</span>
          <button className="z-btn" onClick={() => setZoom(z => Math.min(1.5, +(z + 0.1).toFixed(2)))} title="Zoom in">+</button>
        </div>
        {editMode && (
          <>
            <button className="ghost" onClick={onReset} title="Reset to seed data">Reset</button>
            <button className="primary" onClick={onAddExec}>+ Add leader</button>
          </>
        )}
        <button
          className={editMode ? "edit-toggle is-on" : "edit-toggle"}
          onClick={onToggleEditMode}
          title={editMode ? "Exit edit mode" : "Enter edit mode (PIN required)"}
        >
          {editMode ? (
            <>
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <rect x="3" y="11" width="18" height="11" rx="2"/>
                <path d="M7 11V7a5 5 0 0 1 10 0v4"/>
              </svg>
              <span>Editing</span>
            </>
          ) : (
            <>
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <rect x="3" y="11" width="18" height="11" rx="2"/>
                <path d="M7 11V7a5 5 0 0 1 9.9-1"/>
              </svg>
              <span>Edit</span>
            </>
          )}
        </button>
      </div>
    </header>
  );
}

window.Header = Header;

// =========================================================================
// SYNC STATUS — cloud connection indicator + Publish button
// =========================================================================

function SyncStatus({ sync, editMode, onPublish, onPullLatest }) {
  if (!sync) return null;
  const { status, lastPushedAt, error } = sync;

  // status presets
  const presets = {
    loading: { dot: "is-loading", text: "Loading…" },
    synced:  { dot: "is-ok",      text: "In sync" },
    dirty:   { dot: "is-dirty",   text: "Unsaved changes" },
    pushing: { dot: "is-loading", text: "Publishing…" },
    error:   { dot: "is-err",     text: "Error" },
    offline: { dot: "is-err",     text: "Offline" },
  };
  const p = presets[status] || presets.synced;

  const fmtTime = (ts) => {
    if (!ts) return "";
    const d = new Date(ts);
    const hh = String(d.getHours()).padStart(2, "0");
    const mm = String(d.getMinutes()).padStart(2, "0");
    return `${hh}:${mm}`;
  };

  const tip = error
    ? error
    : (status === "synced" && lastPushedAt
        ? `Published at ${fmtTime(lastPushedAt)}`
        : status === "synced"
          ? "Loaded from GitHub"
          : "");

  return (
    <div className="sync">
      <div className={`sync-pill sync-pill-${status}`} title={tip}>
        <span className={`sync-dot ${p.dot}`} />
        <span className="sync-text">{p.text}</span>
      </div>
      {error && (status === "error" || status === "offline") && (
        <div className="sync-error-msg" title={error}>{error}</div>
      )}
      {editMode && (status === "dirty" || status === "error") && (
        <button
          className="primary sync-publish"
          onClick={onPublish}
          disabled={status === "pushing"}
          title="Save changes to GitHub"
        >
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M12 19V6"/>
            <path d="m6 12 6-6 6 6"/>
            <path d="M5 21h14"/>
          </svg>
          <span>Publish</span>
        </button>
      )}
      {(status === "offline" || status === "error") && !editMode && (
        <button className="ghost sync-publish" onClick={onPullLatest} title="Try again">Retry</button>
      )}
    </div>
  );
}

window.SyncStatus = SyncStatus;

// =========================================================================
// PIN MODAL — gates edit mode behind a 4-digit code
// =========================================================================

const EDIT_PIN = "2026";

function PinModal({ onClose, onSuccess }) {
  const [digits, setDigits] = useS(["", "", "", ""]);
  const [error, setError] = useS(false);
  const [shake, setShake] = useS(false);
  const refs = [useR(null), useR(null), useR(null), useR(null)];

  useE(() => {
    refs[0].current?.focus();
    const onKey = (e) => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, []);

  const tryUnlock = (next) => {
    const code = next.join("");
    if (code.length === 4) {
      if (code === EDIT_PIN) {
        onSuccess();
      } else {
        setError(true);
        setShake(true);
        setTimeout(() => setShake(false), 480);
        setTimeout(() => {
          setDigits(["", "", "", ""]);
          refs[0].current?.focus();
        }, 600);
      }
    }
  };

  const handleChange = (i, v) => {
    const cleaned = v.replace(/\D/g, "").slice(-1);
    const next = [...digits];
    next[i] = cleaned;
    setDigits(next);
    setError(false);
    if (cleaned && i < 3) refs[i + 1].current?.focus();
    if (next.every(d => d !== "")) tryUnlock(next);
  };

  const handleKeyDown = (i, e) => {
    if (e.key === "Backspace" && !digits[i] && i > 0) {
      refs[i - 1].current?.focus();
    }
    if (e.key === "ArrowLeft" && i > 0) refs[i - 1].current?.focus();
    if (e.key === "ArrowRight" && i < 3) refs[i + 1].current?.focus();
  };

  const handlePaste = (e) => {
    e.preventDefault();
    const txt = (e.clipboardData.getData("text") || "").replace(/\D/g, "").slice(0, 4);
    if (!txt) return;
    const next = ["", "", "", ""];
    for (let i = 0; i < txt.length; i++) next[i] = txt[i];
    setDigits(next);
    refs[Math.min(txt.length, 3)].current?.focus();
    if (next.every(d => d !== "")) tryUnlock(next);
  };

  return (
    <div className="scrim" onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}>
      <div className={`modal pin-modal ${shake ? "is-shake" : ""}`} role="dialog" aria-modal="true" aria-label="Enter edit-mode PIN">
        <div className="pin-icon" aria-hidden="true">
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <rect x="3" y="11" width="18" height="11" rx="2"/>
            <path d="M7 11V7a5 5 0 0 1 10 0v4"/>
          </svg>
        </div>
        <h3 className="pin-title">Enter edit-mode PIN</h3>
        <p className="pin-sub">A 4-digit code is required to make changes to the org chart.</p>

        <div className="pin-row" onPaste={handlePaste}>
          {digits.map((d, i) => (
            <input
              key={i}
              ref={refs[i]}
              type="password"
              inputMode="numeric"
              autoComplete="off"
              maxLength={1}
              className={`pin-input ${error ? "is-error" : ""}`}
              value={d}
              onChange={(e) => handleChange(i, e.target.value)}
              onKeyDown={(e) => handleKeyDown(i, e)}
              onFocus={(e) => e.target.select()}
            />
          ))}
        </div>

        <div className={`pin-msg ${error ? "is-error" : ""}`}>
          {error ? "Incorrect code. Try again." : "Press Enter or fill all four digits."}
        </div>

        <div className="pin-actions">
          <button className="ghost" onClick={onClose}>Cancel</button>
        </div>
      </div>
    </div>
  );
}

window.PinModal = PinModal;

// =========================================================================
// AVATAR + MEMBER CHIP
// =========================================================================

function Avatar({ id, name, size = 36, openRole, isLeader }) {
  const tint = tintFor(id || name || "x", !!isLeader);
  if (openRole) {
    return (
      <div className="avatar avatar-open" style={{ width: size, height: size }}>
        <svg width={size * 0.55} height={size * 0.55} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
          <path d="M12 5v14M5 12h14"/>
        </svg>
      </div>
    );
  }
  return (
    <div
      className={`avatar ${isLeader ? "avatar-leader" : ""}`}
      style={{ width: size, height: size, background: tint.bg, color: tint.fg, fontSize: size * 0.36 }}
    >
      {initials(name)}
    </div>
  );
}

function MemberChip({
  member, deptId, onEdit, onRemove, onDrop, query, matched, level, placementCount,
}) {
  const placements = placementCount?.get(member.id) || 0;
  const locked = () => document.body.classList.contains("is-locked");
  return (
    <div
      className={`member ${matched ? "is-match" : ""} ${query && !matched ? "is-dim" : ""} ${level === "lead" ? "is-lead" : ""} ${member.openRole ? "is-open" : ""}`}
      draggable={!locked()}
      onDragStart={(e) => {
        if (locked()) { e.preventDefault(); return; }
        e.dataTransfer.setData("text/plain", JSON.stringify({ kind: "member", id: member.id, fromDeptId: deptId }));
        e.dataTransfer.effectAllowed = "move";
        e.currentTarget.classList.add("dragging");
      }}
      onDragEnd={(e) => e.currentTarget.classList.remove("dragging")}
      onDragOver={(e) => { if (locked()) return; e.preventDefault(); e.currentTarget.classList.add("drop-before"); }}
      onDragLeave={(e) => e.currentTarget.classList.remove("drop-before")}
      onDrop={(e) => {
        if (locked()) return;
        e.preventDefault();
        e.stopPropagation();
        e.currentTarget.classList.remove("drop-before");
        try {
          const data = JSON.parse(e.dataTransfer.getData("text/plain"));
          if (data.kind === "member") onDrop(data, member.id);
        } catch {}
      }}
      onClick={() => { if (locked()) return; onEdit(member); }}
      title={locked() ? member.name : (placements > 1 ? `Click to edit · also in ${placements - 1} other dept${placements - 1 === 1 ? "" : "s"}` : "Click to edit · drag to move")}
    >
      <Avatar id={member.id} name={member.name} openRole={member.openRole} isLeader={member.isLeader} />
      <div className="m-text">
        <div className="m-name">
          <Highlight text={member.name} query={query} />
          {level === "lead" && <span className="lead-dot" title="Lead" />}
          {placements > 1 && (
            <span className="multi-badge" title={`Placed in ${placements} departments`}>
              <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
                <path d="M10 13a5 5 0 0 0 7.07 0l3-3a5 5 0 0 0-7.07-7.07l-1 1"/>
                <path d="M14 11a5 5 0 0 0-7.07 0l-3 3a5 5 0 0 0 7.07 7.07l1-1"/>
              </svg>
              ×{placements}
            </span>
          )}
        </div>
        <div className="m-role">
          <Highlight text={member.role} query={query} />
        </div>
      </div>
      <button className="m-remove" onClick={(e) => { e.stopPropagation(); onRemove(member.id); }} title="Remove from this department">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6L6 18M6 6l12 12"/></svg>
      </button>
    </div>
  );
}

window.Avatar = Avatar;
window.MemberChip = MemberChip;

// =========================================================================
// BOARD STRIP
// =========================================================================

function BoardStrip({ board, query, matchSet, placementCount, onEditPerson, onAddPerson, onRemove, onMove }) {
  const handleDrop = (data, beforeId) => {
    if (data.kind !== "member") return;
    const idx = beforeId
      ? board.members.findIndex(m => m.id === beforeId)
      : board.members.length;
    onMove(data.id, data.fromDeptId, "board", idx);
  };

  return (
    <section className="board"
      onDragOver={(e) => { e.preventDefault(); e.currentTarget.classList.add("drop-target"); }}
      onDragLeave={(e) => e.currentTarget.classList.remove("drop-target")}
      onDrop={(e) => {
        e.preventDefault();
        e.currentTarget.classList.remove("drop-target");
        try {
          const data = JSON.parse(e.dataTransfer.getData("text/plain"));
          handleDrop(data, null);
        } catch {}
      }}
    >
      <div className="board-head">
        <div className="board-eyebrow">Governance</div>
        <h2 className="board-title">Board of Directors</h2>
        <div className="board-meta">{board.members.length} member{board.members.length === 1 ? "" : "s"}</div>
      </div>
      <div className="board-list">
        {board.members.map(m => (
          <MemberChip
            key={m.id}
            member={m}
            deptId="board"
            query={query}
            matched={matchSet ? matchSet.has(m.id) : false}
            placementCount={placementCount}
            onEdit={onEditPerson}
            onRemove={onRemove}
            onDrop={handleDrop}
          />
        ))}
        <button className="member member-add" onClick={onAddPerson}>
          <div className="avatar avatar-add"><span>+</span></div>
          <div className="m-text"><div className="m-name">Add board member</div></div>
        </button>
      </div>
    </section>
  );
}

window.BoardStrip = BoardStrip;

// =========================================================================
// EXEC COLUMN (CEO/COO/CTO/...)
// =========================================================================

function ExecColumn({
  exec, allExecs, query, matchSet, placementCount,
  onEditExec, onRemoveExec, onAddDept,
  onEditDept, onRemoveDept,
  onAddPersonToDept, onEditPerson, onRemovePerson, onMovePerson, onMoveDept,
}) {
  const matched = matchSet ? matchSet.has(exec.id) : false;
  const headcount = exec.departments.reduce(
    (s, d) => s + d.leads.length + d.members.length, 0
  );

  return (
    <div
      className={`exec-col ${query && !matched && !exec.departments.some(d => matchSet?.has(d.id) || d.members.some(m => matchSet?.has(m.id)) || d.leads.some(m => matchSet?.has(m.id))) ? "col-dim" : ""}`}
      onDragOver={(e) => {
        try {
          const types = e.dataTransfer.types;
          if (types && types.includes("text/plain")) {
            e.preventDefault();
          }
        } catch {}
      }}
      onDrop={(e) => {
        try {
          const data = JSON.parse(e.dataTransfer.getData("text/plain"));
          if (data.kind === "dept" && data.fromExecId !== exec.id) {
            e.preventDefault();
            onMoveDept(data.fromExecId, data.id, exec.id);
          }
        } catch {}
      }}
    >
      <div
        className={`exec-card ${matched ? "is-match" : ""}`}
        onClick={() => { if (document.body.classList.contains("is-locked")) return; onEditExec(exec); }}
        title={document.body.classList.contains("is-locked") ? exec.name : "Click to edit"}
      >
        <div className="exec-head">
          <Avatar id={exec.personId || exec.id} name={exec.name} size={48} isLeader />
          <div className="exec-meta">
            <div className="exec-title"><Highlight text={exec.title} query={query} /></div>
            <div className="exec-name"><Highlight text={exec.name} query={query} /></div>
          </div>
          <button className="exec-remove" onClick={(e) => { e.stopPropagation(); onRemoveExec(); }} title="Remove leader column">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6L6 18M6 6l12 12"/></svg>
          </button>
        </div>
        {exec.tag && <div className="exec-tag"><Highlight text={exec.tag} query={query} /></div>}
        <div className="exec-stats">
          <span><strong>{exec.departments.length}</strong> dept{exec.departments.length === 1 ? "" : "s"}</span>
          <span className="dot">·</span>
          <span><strong>{headcount}</strong> placement{headcount === 1 ? "" : "s"}</span>
        </div>
      </div>

      <div className="exec-spine" aria-hidden="true" />

      <div className="dept-list">
        {exec.departments.map((d, di) => (
          <Department
            key={d.id}
            dept={d}
            execId={exec.id}
            execIndex={di}
            allExecs={allExecs}
            query={query}
            matchSet={matchSet}
            placementCount={placementCount}
            onEditDept={onEditDept}
            onRemoveDept={onRemoveDept}
            onAddPerson={onAddPersonToDept}
            onEditPerson={onEditPerson}
            onRemovePerson={onRemovePerson}
            onMovePerson={onMovePerson}
            onMoveDept={onMoveDept}
          />
        ))}
        <button className="dept-add" onClick={onAddDept}>
          <span className="plus">+</span> Add department
        </button>
      </div>
    </div>
  );
}

window.ExecColumn = ExecColumn;

// =========================================================================
// DEPARTMENT
// =========================================================================

function Department({
  dept, execId, allExecs, query, matchSet, placementCount,
  onEditDept, onRemoveDept,
  onAddPerson, onEditPerson, onRemovePerson, onMovePerson, onMoveDept,
}) {
  const [over, setOver] = useS(false);
  const matched = matchSet ? matchSet.has(dept.id) : false;
  const anyMemberMatch =
    dept.members.some(m => matchSet?.has(m.id)) ||
    dept.leads.some(m => matchSet?.has(m.id));

  const handleMemberDrop = (data, beforeMemberId, asLead) => {
    if (data.kind !== "member") return;
    const list = asLead ? dept.leads : dept.members;
    const idx = beforeMemberId
      ? list.findIndex(m => m.id === beforeMemberId)
      : list.length;
    onMovePerson(data.id, data.fromDeptId, dept.id, idx, asLead);
  };

  const totalCount = dept.leads.length + dept.members.length;

  return (
    <div
      className={`dept ${over ? "is-over" : ""} ${(matched || anyMemberMatch) ? "is-match" : ""} ${query && !matched && !anyMemberMatch ? "is-dim" : ""}`}
      draggable={!document.body.classList.contains("is-locked")}
      onDragStart={(e) => {
        if (document.body.classList.contains("is-locked")) { e.preventDefault(); return; }
        e.stopPropagation();
        e.dataTransfer.setData("text/plain", JSON.stringify({ kind: "dept", id: dept.id, fromExecId: execId }));
        e.dataTransfer.effectAllowed = "move";
        e.currentTarget.classList.add("dept-dragging");
      }}
      onDragEnd={(e) => e.currentTarget.classList.remove("dept-dragging")}
      onDragOver={(e) => {
        if (document.body.classList.contains("is-locked")) return;
        e.preventDefault();
        setOver(true);
      }}
      onDragLeave={() => setOver(false)}
      onDrop={(e) => {
        if (document.body.classList.contains("is-locked")) return;
        setOver(false);
        e.preventDefault();
        e.stopPropagation();
        try {
          const data = JSON.parse(e.dataTransfer.getData("text/plain"));
          if (data.kind === "member") {
            // Default drop into Team list
            handleMemberDrop(data, null, false);
          }
        } catch {}
      }}
    >
      <div className="dept-head">
        <div className="dept-grip" title="Drag department">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <circle cx="9" cy="6" r="1"/><circle cx="9" cy="12" r="1"/><circle cx="9" cy="18" r="1"/>
            <circle cx="15" cy="6" r="1"/><circle cx="15" cy="12" r="1"/><circle cx="15" cy="18" r="1"/>
          </svg>
        </div>
        <div className="dept-meta">
          <div className="dept-name"><Highlight text={dept.name} query={query} /></div>
          {(dept.subtitle || dept.note) && (
            <div className="dept-sub">
              <Highlight text={dept.subtitle || dept.note} query={query} />
            </div>
          )}
        </div>
        <div className="dept-count">{totalCount}</div>
        <div className="dept-actions">
          <button className="icon-btn" onClick={(e) => { e.stopPropagation(); onEditDept(dept); }} title="Edit department">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg>
          </button>
          <button className="icon-btn" onClick={(e) => { e.stopPropagation(); onRemoveDept(dept); }} title="Delete department">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M8 6V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/></svg>
          </button>
        </div>
      </div>

      <div className="dept-body">
        {totalCount === 0 ? (
          <div className="dept-empty">
            <span>No members yet</span>
          </div>
        ) : (
          <>
            {dept.leads.length > 0 && (
              <>
                <div className="section-label">Leads</div>
                {dept.leads.map(m => (
                  <MemberChip
                    key={m.id}
                    member={m}
                    deptId={dept.id}
                    query={query}
                    matched={matchSet ? matchSet.has(m.id) : false}
                    placementCount={placementCount}
                    level="lead"
                    onEdit={(mem) => onEditPerson(dept, mem)}
                    onRemove={(personId) => onRemovePerson(personId, dept.id)}
                    onDrop={(data, beforeId) => handleMemberDrop(data, beforeId, true)}
                  />
                ))}
              </>
            )}
            {dept.members.length > 0 && (
              <>
                {dept.leads.length > 0 && <div className="section-label">Team</div>}
                {dept.members.map(m => (
                  <MemberChip
                    key={m.id}
                    member={m}
                    deptId={dept.id}
                    query={query}
                    matched={matchSet ? matchSet.has(m.id) : false}
                    placementCount={placementCount}
                    onEdit={(mem) => onEditPerson(dept, mem)}
                    onRemove={(personId) => onRemovePerson(personId, dept.id)}
                    onDrop={(data, beforeId) => handleMemberDrop(data, beforeId, false)}
                  />
                ))}
              </>
            )}
          </>
        )}
        <div className="dept-add-row">
          <button className="dept-add-person" onClick={() => onAddPerson(dept, true)} title="Add a lead from People">
            <span className="plus">+</span> Lead
          </button>
          <button className="dept-add-person" onClick={() => onAddPerson(dept, false)} title="Add a team member from People">
            <span className="plus">+</span> Team
          </button>
        </div>
      </div>
    </div>
  );
}

window.Department = Department;

// =========================================================================
// PEOPLE SIDEBAR — master list of all people in the org
// =========================================================================

function PeopleSidebar({ people, placementCount, editMode, onAdd, onEdit, onDelete, query, matchSet }) {
  const [localQuery, setLocalQuery] = useS("");
  const [filter, setFilter] = useS("all"); // all | unplaced | leaders

  const sorted = React.useMemo(() => {
    const sorted = [...people].sort((a, b) => (a.name || "").localeCompare(b.name || ""));
    return sorted;
  }, [people]);

  const filtered = sorted.filter(p => {
    const placements = placementCount.get(p.id) || 0;
    if (filter === "unplaced" && placements > 0) return false;
    if (filter === "leaders" && !p.isLeader) return false;
    if (localQuery) {
      const q = localQuery.toLowerCase();
      if (!(p.name || "").toLowerCase().includes(q) && !(p.role || "").toLowerCase().includes(q)) {
        return false;
      }
    }
    return true;
  });

  const totalUnplaced = people.filter(p => !placementCount.get(p.id)).length;

  return (
    <aside className="people-sidebar">
      <div className="ps-head">
        <div className="ps-title-row">
          <h2 className="ps-title">People</h2>
          <span className="ps-total">{people.length}</span>
        </div>
        <p className="ps-sub">Single source of truth. Add, edit, or remove people here — they show up on the chart only when placed.</p>
      </div>

      <div className="ps-search">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <circle cx="11" cy="11" r="7"/><path d="m20 20-3.5-3.5"/>
        </svg>
        <input
          type="text"
          placeholder="Filter people…"
          value={localQuery}
          onChange={(e) => setLocalQuery(e.target.value)}
        />
        {localQuery && (
          <button className="ps-clear" onClick={() => setLocalQuery("")} title="Clear">×</button>
        )}
      </div>

      <div className="ps-tabs">
        <button className={`ps-tab ${filter === "all" ? "is-on" : ""}`} onClick={() => setFilter("all")}>All</button>
        <button className={`ps-tab ${filter === "unplaced" ? "is-on" : ""}`} onClick={() => setFilter("unplaced")}>
          Unplaced {totalUnplaced > 0 && <span className="ps-badge">{totalUnplaced}</span>}
        </button>
        <button className={`ps-tab ${filter === "leaders" ? "is-on" : ""}`} onClick={() => setFilter("leaders")}>Leaders</button>
      </div>

      <div className="ps-list">
        {filtered.length === 0 ? (
          <div className="ps-empty">
            {localQuery ? "No people match this filter." : (filter === "unplaced" ? "Everyone is placed on the chart." : "No people yet.")}
          </div>
        ) : (
          filtered.map(p => {
            const placements = placementCount.get(p.id) || 0;
            const matched = matchSet ? matchSet.has(p.id) : false;
            return (
              <div
                key={p.id}
                className={`ps-row ${matched ? "is-match" : ""} ${placements === 0 ? "is-unplaced" : ""}`}
                draggable={editMode}
                onDragStart={(e) => {
                  if (!editMode) return;
                  e.dataTransfer.setData("text/plain", JSON.stringify({ kind: "member", id: p.id, fromDeptId: null }));
                  e.dataTransfer.effectAllowed = "copy";
                  e.currentTarget.classList.add("dragging");
                }}
                onDragEnd={(e) => e.currentTarget.classList.remove("dragging")}
                onClick={() => editMode && onEdit(p)}
                title={editMode ? (placements ? `${placements} placement${placements === 1 ? "" : "s"} · click to edit · drag to add to chart` : "Unplaced · click to edit · drag to add to chart") : (placements ? `${placements} placement${placements === 1 ? "" : "s"}` : "Unplaced")}
              >
                <Avatar id={p.id} name={p.name} size={32} openRole={p.openRole} isLeader={p.isLeader} />
                <div className="ps-text">
                  <div className="ps-name">
                    <Highlight text={p.name} query={query || localQuery} />
                    {p.isLeader && <span className="ps-leader-pip" title="Leader">★</span>}
                  </div>
                  <div className="ps-role">
                    <Highlight text={p.role} query={query || localQuery} />
                  </div>
                </div>
                <div className="ps-meta">
                  {placements > 0 ? (
                    <span className="ps-count" title={`Placed in ${placements} place${placements === 1 ? "" : "s"}`}>×{placements}</span>
                  ) : (
                    <span className="ps-count is-zero">·</span>
                  )}
                  {editMode && (
                    <button
                      className="icon-btn"
                      onClick={(e) => { e.stopPropagation(); onDelete(p); }}
                      title="Delete person"
                    >
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M8 6V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/></svg>
                    </button>
                  )}
                </div>
              </div>
            );
          })
        )}
      </div>

      {editMode && (
        <button className="ps-add" onClick={onAdd}>
          <span className="plus">+</span> Add person
        </button>
      )}
    </aside>
  );
}

window.PeopleSidebar = PeopleSidebar;
